        featuredImage: "media/facebook-archive/fb-287-fonduetram-de-berna-fondue-sobre-ra-lessi-te-apetece-un-plan-diferente-este-invierno-en-berna-vuelve-el-famoso-fonduetram-una-cena-de-fondue-dentro.jpg",
